import React, { useState, useEffect } from 'react';
import { Link, useLocation } from 'react-router-dom';
import { CONTACT_INFO } from '../constants';

const Header: React.FC = () => {
  const [isMenuOpen, setIsMenuOpen] = useState(false);
  const [scrolled, setScrolled] = useState(false);
  const location = useLocation();

  useEffect(() => {
    const handleScroll = () => setScrolled(window.scrollY > 50);
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  const menuItems = [
    { name: '공간소개', path: '/' },
    { name: '상주사무실', path: '/resident' },
    { name: '비상주사무실', path: '/virtual' },
    { name: '회의실', path: '/meeting' },
    { name: '갤러리', path: '/gallery' },
    { name: '위치안내', path: '/location' },
    { name: '블로그', path: '/blog' },
  ];

  return (
    <header className={`fixed top-0 left-0 w-full z-50 transition-all duration-300 ${scrolled ? 'bg-brand-bg shadow-md py-3' : 'bg-transparent py-5'}`}>
      <div className="container mx-auto px-4 flex justify-between items-center">
        <Link to="/" className="text-2xl font-heading text-brand-primary tracking-tighter flex items-center">
          <span className="mr-2">NOW</span>
          <span className="text-sm font-body border-l border-brand-primary pl-2 opacity-80">동탄공유오피스 나우</span>
        </Link>

        {/* Desktop Nav */}
        <nav className="hidden md:flex space-x-8">
          {menuItems.map((item) => (
            <Link
              key={item.path}
              to={item.path}
              className={`text-sm font-medium transition-colors hover:text-brand-accent ${location.pathname === item.path ? 'text-brand-accent font-semibold' : 'text-brand-text'}`}
            >
              {item.name}
            </Link>
          ))}
        </nav>

        <Link to="/contact" className="hidden md:block bg-brand-primary text-white px-6 py-2 rounded-full text-sm font-medium hover:bg-opacity-90 transition-all">
          투어 예약하기
        </Link>

        {/* Mobile Toggle */}
        <button className="md:hidden text-brand-primary" onClick={() => setIsMenuOpen(!isMenuOpen)}>
          <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d={isMenuOpen ? "M6 18L18 6M6 6l12 12" : "M4 6h16M4 12h16M4 18h16"} />
          </svg>
        </button>
      </div>

      {/* Mobile Menu */}
      {isMenuOpen && (
        <div className="md:hidden absolute top-full left-0 w-full bg-brand-bg shadow-xl border-t border-brand-border animate-fade-in">
          <div className="flex flex-col p-6 space-y-4">
            {menuItems.map((item) => (
              <Link
                key={item.path}
                to={item.path}
                onClick={() => setIsMenuOpen(false)}
                className="text-lg font-medium border-b border-brand-border pb-2"
              >
                {item.name}
              </Link>
            ))}
            <Link to="/contact" className="bg-brand-primary text-white text-center py-3 rounded-lg font-medium" onClick={() => setIsMenuOpen(false)}>
              상담 신청하기
            </Link>
          </div>
        </div>
      )}
    </header>
  );
};

